script:
frappe.ui.form.on('OT Adjustment', {
    refresh: function(frm) {
        setTimeout(function() {
            var field = frm.fields_dict['month'];
            if (!field || !field.datepicker) return;

            var months = [
                "January", "February", "March", "April",
                "May", "June", "July", "August",
                "September", "October", "November", "December"
            ];

            field.datepicker.update({
                view: 'months',
                minView: 'months',
                onSelect: function(fd, date, picker) {
                    if (!date) return;
                    var firstDay = new Date(date.getFullYear(), date.getMonth(), 1);
                    var dateStr = frappe.datetime.obj_to_str(firstDay);
                    frm.doc.month = dateStr;
                    frm.dirty();
                    field.$input.val(months[date.getMonth()] + ' ' + date.getFullYear());
                    picker.hide();
                }
            });

            if (frm.doc.month) {
                var d = frappe.datetime.str_to_obj(frm.doc.month);
                if (d) {
                    field.$input.val(months[d.getMonth()] + ' ' + d.getFullYear());
                }
            }
        }, 300);
    }
});
